// // This module compares two 4-bit binary inputs and outputs three signals indicating if the first input is less than, greater than, or equal to the second input.
module comparator_4bit(
  input [3:0] a,
  input [3:0] b,
  output reg gt,
  output reg lt,
  output reg eq
);

  always @(*) begin
    gt = (a > b);
    lt = (a < b);
    eq = (a == b);
  end

endmodule
